    response.data = input.map(b => ({
      name: b.name,
      protected: b.protected
    }));
    response.message = `Found ${input.length} branches`;
  } else if (operation === 'list-pulls') {
    response.data = input.map(pr => ({
      number: pr.number,
      title: pr.title,
      author: pr.user?.login,
      state: pr.state,
      created: pr.created_at
    }));
    response.message = `Found ${input.length} open PRs`;
  }
} else if (input.number) {
  // Issue created
  response.data = {
    number: input.number,
    title: input.title,
    url: input.html_url
  };
  response.message = `Issue #${input.number} created`;
} else if (operation === 'trigger-workflow') {
  response.message = 'GitHub Action triggered successfully';
  response.data = { workflow_id: $('Normalize Input').first().json.workflow_id };
} else {
  response.message = 'Operation completed';
  response.data = input;
}

return { json: response };"
