"jsCode": "const invoices = $('Odoo — Get Posted Invoices/Bills').all().map(i => i.json);
const taxLines = $('Odoo — Get Tax Lines').all().map(i => i.json);
const flat_inv = Array.isArray(invoices[0]) ? invoices[0] : invoices;
const flat_tax = Array.isArray(taxLines[0]) ? taxLines[0] : taxLines;
const dates = $('Calculate Date Range').first().json;

// Classify invoices
const sales = flat_inv.filter(i => i.move_type === 'out_invoice' || i.move_type === 'out_refund');
const purchases = flat_inv.filter(i => i.move_type === 'in_invoice' || i.move_type === 'in_refund');

// VAT validation
const issues = [];
let vatTotal = 0;
let ewtTotal = 0;

for (const inv of flat_inv) {
  if (!inv || !inv.id) continue;
  const taxAmt = inv.amount_tax || 0;
  const untaxed = inv.amount_untaxed || 0;

  // Check if VAT is applied (12% standard PH rate)
  if (untaxed > 0 && taxAmt === 0) {
    issues.push({
      type: 'missing_vat',
      severity: 'high',
      invoice: inv.name,
      partner: Array.isArray(inv.partner_id) ? inv.partner_id[1] : inv.partner_id,
      amount: untaxed,
      message: `No tax applied on ${inv.name} (${inv.move_type}) — amount: PHP ${untaxed.toFixed(2)}`
    });
  }

  // Check VAT rate reasonableness (should be ~12% of untaxed)
  if (untaxed > 0 && taxAmt > 0) {
    const effectiveRate = (taxAmt / untaxed) * 100;
    if (effectiveRate < 10 || effectiveRate > 15) {
      issues.push({
        type: 'unusual_tax_rate',
        severity: 'medium',
        invoice: inv.name,
        partner: Array.isArray(inv.partner_id) ? inv.partner_id[1] : inv.partner_id,
        effective_rate: effectiveRate.toFixed(2),
        message: `Unusual tax rate ${effectiveRate.toFixed(2)}% on ${inv.name} (expected ~12% VAT)`
      });
    }
    vatTotal += taxAmt;
  }

  // Check fiscal position for vendor bills (EWT)
  if ((inv.move_type === 'in_invoice' || inv.move_type === 'in_refund') && !inv.fiscal_position_id) {
    issues.push({
      type: 'missing_fiscal_position',
      severity: 'medium',
      invoice: inv.name,
      partner: Array.isArray(inv.partner_id) ? inv.partner_id[1] : inv.partner_id,
      message: `No fiscal position on vendor bill ${inv.name} — EWT may not be applied correctly`
    });
  }
}

