const month = dates.current_month_num;
const year = dates.current_year;
const deadlines = [
  { form: '2550M', desc: 'Monthly VAT Return', deadline: `${year}-${String(month).padStart(2,'0')}-20`, penalty: 'Surcharge 25% + Interest 12% p.a.' },
  { form: '2550Q', desc: 'Quarterly VAT Return (if quarter-end)', deadline: month % 3 === 1 ? `${year}-${String(month).padStart(2,'0')}-25` : 'N/A', penalty: 'Surcharge 25% + Interest 12% p.a.' },
  { form: '0619E', desc: 'Monthly EWT Remittance', deadline: `${year}-${String(month).padStart(2,'0')}-10`, penalty: 'Surcharge 25% + Interest 12% p.a. + Compromise' },
  { form: '1601C', desc: 'Monthly Withholding Tax on Compensation', deadline: `${year}-${String(month).padStart(2,'0')}-10`, penalty: 'Surcharge 25% + Interest 12% p.a.' },
  { form: '2307', desc: 'Certificate of Creditable Tax Withheld (issue to vendor)', deadline: `${year}-${String(month).padStart(2,'0')}-20`, penalty: 'PHP 1,000 per certificate' }
].filter(d => d.deadline !== 'N/A');

return [{ json: {
