    },
    {
      "parameters": {

"jsCode": "// BIR Tax Calendar - Philippine Tax Deadlines
const today = new Date();
const currentMonth = today.getMonth() + 1;
const currentDay = today.getDate();
const currentYear = today.getFullYear();

// Helper to calculate deadline
function getDeadline(day, monthOffset = 0) {
  const deadline = new Date(currentYear, currentMonth - 1 + monthOffset, day);
  return deadline;
}

// Helper to check if deadline is within N days
function isWithinDays(deadline, days) {
  const diff = Math.ceil((deadline - today) / (1000 * 60 * 60 * 24));
  return diff >= 0 && diff <= days;
}

const deadlines = [];

// Monthly deadlines
const monthlyDeadlines = [
  { form: '1601-C', name: 'Monthly Withholding Tax', day: 10, description: 'Compensation withholding tax' },
  { form: '1601-E', name: 'Monthly Expanded Withholding Tax', day: 10, description: 'EWT on payments to contractors' },
  { form: '2550M', name: 'Monthly VAT Declaration', day: 20, description: 'Monthly VAT (if applicable)' },
  { form: '1606', name: 'Monthly Final Withholding Tax', day: 10, description: 'Final tax on dividends, royalties' },
];

monthlyDeadlines.forEach(d => {
  const deadline = getDeadline(d.day, 1); // Next month
  if (isWithinDays(deadline, 7)) {
    deadlines.push({
      ...d,
      deadline: deadline.toISOString().split('T')[0],
      daysUntil: Math.ceil((deadline - today) / (1000 * 60 * 60 * 24)),
      priority: Math.ceil((deadline - today) / (1000 * 60 * 60 * 24)) <= 3 ? 'high' : 'medium',
    });
  }
});

// Quarterly deadlines (if in quarter-end month)
if ([3, 6, 9, 12].includes(currentMonth)) {
  const quarterlyDeadlines = [
    { form: '2550Q', name: 'Quarterly VAT Return', day: 25, description: 'Quarterly VAT declaration' },
    { form: '1601-Q', name: 'Quarterly Income Tax', day: 15, description: 'Quarterly income tax' },
    { form: '1701Q', name: 'Quarterly Income Tax (Individuals)', day: 15, description: 'For self-employed' },
  ];

  quarterlyDeadlines.forEach(d => {
    const deadline = getDeadline(d.day, 1);
    if (isWithinDays(deadline, 14)) {
      deadlines.push({
        ...d,
        deadline: deadline.toISOString().split('T')[0],
        daysUntil: Math.ceil((deadline - today) / (1000 * 60 * 60 * 24)),
        priority: Math.ceil((deadline - today) / (1000 * 60 * 60 * 24)) <= 5 ? 'high' : 'medium',
      });
    }
  });
}

// Annual deadlines (January-April)
if (currentMonth >= 1 && currentMonth <= 4) {
  const annualDeadlines = [
