        "jsCode": "// Aggregate and format finance report
const raw = $input.first().json;
const queryMeta = $('Build Query').first().json;
const records = raw.result || [];

if (raw.error) {
  return [{ json: { status: 'error', message: raw.error.data?.message || 'Query failed' } }];
}

let summary = {};

switch (queryMeta.report_type) {
  case 'ar_aging':
  case 'ap_aging': {
    const now = new Date();
    const buckets = { current: 0, '1_30': 0, '31_60': 0, '61_90': 0, over_90: 0 };
    let total = 0;
    records.forEach(r => {
      const due = new Date(r.invoice_date_due || r.date);
      const days = Math.floor((now - due) / 86400000);
      const amt = r.amount_residual || 0;
      total += amt;
      if (days <= 0) buckets.current += amt;
      else if (days <= 30) buckets['1_30'] += amt;
      else if (days <= 60) buckets['31_60'] += amt;
      else if (days <= 90) buckets['61_90'] += amt;
      else buckets.over_90 += amt;
    });
    summary = { aging_buckets: buckets, total_outstanding: total, invoice_count: records.length };
    break;
  }
  case 'invoice_stats':
  case 'payment_stats': {
    const total = records.reduce((s, r) => s + (r.amount_total || r.amount || 0), 0);
    summary = { total_amount: total, record_count: records.length, records: records.slice(0, 50) };
    break;
  }
  default:
    summary = { record_count: records.length, records: records.slice(0, 100) };
}

return [{
  json: {
    status: 'success',
    source: 'odoo_sor',
    report_type: queryMeta.report_type,
    period: queryMeta.period,
    date_range: { from: queryMeta.date_from, to: queryMeta.date_to },
    ...summary
  }
}];"
