"jsCode": "const cfg = $('Route GitHub Action').first().json;
const GH_TOKEN = $env.GITHUB_TOKEN;

if (!GH_TOKEN) {
  return [{ json: { status:'error', message:'GITHUB_TOKEN not set in n8n env vars' } }];
}

const headers = {
  'Authorization': `Bearer ${GH_TOKEN}`,
  'Accept': 'application/vnd.github.v3+json',
  'Content-Type': 'application/json',
  'X-GitHub-Api-Version': '2022-11-28'
};

try {
  // ---- SIMPLE GET/POST/PUT/DELETE ----
  if (['GET','POST','PUT','DELETE','PATCH'].includes(cfg.method)) {
    const opts = { method: cfg.method, headers };
    if (cfg.body) opts.body = JSON.stringify(cfg.body);

    const resp = await fetch(cfg.url, opts);
    const data = await resp.json();

    if (!resp.ok) {
      return [{ json: { status:'error', code: resp.status, message: data.message || 'GitHub API error', detail: data } }];
    }
    return [{ json: { status:'ok', action: cfg.action, repo: cfg.repo, data } }];
  }

  // ---- UPDATE FILE (GET SHA then PUT) ----
  if (cfg.method === 'GET_THEN_PUT') {
    const getResp = await fetch(cfg.get_url, { method:'GET', headers });
    const fileInfo = await getResp.json();

    if (!getResp.ok) {
      return [{ json: { status:'error', message: `File not found: ${fileInfo.message}` } }];
    }

    const putResp = await fetch(cfg.put_url, {
      method: 'PUT', headers,
      body: JSON.stringify({
        message: cfg.commit_message,
        content: cfg.content_b64,
        sha: fileInfo.sha,
        branch: cfg.branch
      })
    });
    const putData = await putResp.json();

    if (!putResp.ok) {
      return [{ json: { status:'error', code: putResp.status, message: putData.message } }];
    }
    return [{ json: { status:'ok', action: cfg.action, repo: cfg.repo, data: putData } }];
  }

  // ---- CREATE BRANCH (GET base SHA then POST ref) ----
  if (cfg.method === 'CREATE_BRANCH') {
    const refResp = await fetch(cfg.base_ref_url, { method:'GET', headers });
    const refData = await refResp.json();

    if (!refResp.ok) {
      return [{ json: { status:'error', message: `Base branch not found: ${refData.message}` } }];
    }

    const sha = refData.object?.sha;
    const createResp = await fetch(cfg.create_ref_url, {
      method: 'POST', headers,
      body: JSON.stringify({ ref: `refs/heads/${cfg.new_branch}`, sha })
    });
    const createData = await createResp.json();

    if (!createResp.ok) {
      return [{ json: { status:'error', code: createResp.status, message: createData.message } }];
    }
    return [{ json: { status:'ok', action: cfg.action, repo: cfg.repo, data: createData } }];
  }

  return [{ json: { status:'error', message: 'Unhandled method type' } }];

} catch (e) {
  return [{ json: { status:'error', message: e.message } }];
}"
