"jsCode": "const plan = $('Plan Deployment').first().json;
const GH_TOKEN = $env.GITHUB_TOKEN;
const N8N_URL = $env.N8N_API_URL || 'https://n8n.insightpulseai.com';
const N8N_KEY = $env.N8N_API_KEY;

const results = { steps: [], errors: [] };

const ghHeaders = {
  'Authorization': `Bearer ${GH_TOKEN}`,
  'Accept': 'application/vnd.github.v3+json',
  'Content-Type': 'application/json',
  'X-GitHub-Api-Version': '2022-11-28'
};
const n8nHeaders = {
  'X-N8N-API-KEY': N8N_KEY,
  'Content-Type': 'application/json'
};

const [owner, repoName] = plan.repo.split('/');
let targetBranch = plan.branch;
let prUrl = null;

try {
  // ── STEP 0: If full_deploy with PR, create branch first ──
  if (plan.mode === 'full_deploy' && plan.prTitle) {
    const branchName = `deploy/${plan.slug}-${Date.now()}`;

    // Get base SHA
    const baseResp = await fetch(`https://api.github.com/repos/${owner}/${repoName}/git/ref/heads/${plan.branch}`, { headers: ghHeaders });
    const baseData = await baseResp.json();

    if (baseResp.ok) {
      const createResp = await fetch(`https://api.github.com/repos/${owner}/${repoName}/git/refs`, {
        method: 'POST', headers: ghHeaders,
        body: JSON.stringify({ ref: `refs/heads/${branchName}`, sha: baseData.object.sha })
      });
      if (createResp.ok) {
        targetBranch = branchName;
        results.steps.push({ step: 'create_branch', branch: branchName, status: 'ok' });
      } else {
        results.errors.push({ step: 'create_branch', error: (await createResp.json()).message });
      }
    }
  }

  // ── STEP 1: Deploy to n8n (if workflow mode) ──
  if (['deploy_workflow', 'full_deploy'].includes(plan.mode)) {
    let wfJson;
    try {
      wfJson = JSON.parse(plan.content);
    } catch (e) {
      wfJson = { name: plan.name, nodes: [], connections: {}, settings: {} };
      results.errors.push({ step: 'parse_workflow', warning: 'Content is not valid n8n JSON; created empty workflow shell' });
    }

    const createResp = await fetch(`${N8N_URL}/api/v1/workflows`, {
      method: 'POST', headers: n8nHeaders,
      body: JSON.stringify(wfJson)
    });
    const createData = await createResp.json();

    if (createResp.ok) {
      const wf = createData.data?.[0] || createData;
      results.steps.push({
        step: 'create_n8n_workflow',
        workflow_id: wf.id,
        name: wf.name,
        url: `${N8N_URL}/workflow/${wf.id}`,
        status: 'ok'
      });

      // Optionally activate
      if (plan.activateWorkflow) {
        await fetch(`${N8N_URL}/api/v1/workflows/${wf.id}`, {
          method: 'PATCH', headers: n8nHeaders,
          body: JSON.stringify({ active: true })
        });
        results.steps.push({ step: 'activate_workflow', status: 'ok' });
      }
    } else {
      results.errors.push({ step: 'create_n8n_workflow', error: createData.message || 'Failed' });
    }
  }

  // ── STEP 2: Commit to GitHub ──
  if (GH_TOKEN) {
    const contentB64 = Buffer.from(plan.content).toString('base64');

    // Check if file exists (to get SHA for update)
    const checkResp = await fetch(
      `https://api.github.com/repos/${owner}/${repoName}/contents/${plan.ghPath}?ref=${targetBranch}`,
      { headers: ghHeaders }
    );

    let putBody = {
      message: plan.commitMsg,
      content: contentB64,
      branch: targetBranch
    };

    if (checkResp.ok) {
      const existing = await checkResp.json();
      putBody.sha = existing.sha; // update
    }

    const commitResp = await fetch(
      `https://api.github.com/repos/${owner}/${repoName}/contents/${plan.ghPath}`,
      { method: 'PUT', headers: ghHeaders, body: JSON.stringify(putBody) }
    );
    const commitData = await commitResp.json();

    if (commitResp.ok) {
      results.steps.push({
        step: 'github_commit',
        path: plan.ghPath,
        sha: commitData.commit?.sha,
        url: commitData.content?.html_url,
        status: 'ok'
      });
    } else {
      results.errors.push({ step: 'github_commit', error: commitData.message });
    }
  } else {
    results.errors.push({ step: 'github_commit', error: 'GITHUB_TOKEN not set' });
  }

  // ── STEP 3: Create issue (optional) ──
  if (plan.createIssue && GH_TOKEN) {
    const labels = plan.issueLabels ? plan.issueLabels.split(',').map(l=>l.trim()) : ['automation'];
    const fileUrl = results.steps.find(s=>s.step==='github_commit')?.url || '';
    const n8nUrl = results.steps.find(s=>s.step==='create_n8n_workflow')?.url || '';

    const issueBody = `## Deployed Artifact: ${plan.name}\n\n` +
      `**Mode:** ${plan.mode}\n` +
      (fileUrl ? `**GitHub:** ${fileUrl}\n` : '') +
      (n8nUrl ? `**n8n Workflow:** ${n8nUrl}\n` : '') +
      `**Branch:** ${targetBranch}\n\n` +
      `Deployed via Claude.ai MCP artifact deployer.`;

    const issueResp = await fetch(`https://api.github.com/repos/${owner}/${repoName}/issues`, {
      method: 'POST', headers: ghHeaders,
      body: JSON.stringify({ title: `[Deploy] ${plan.name}`, body: issueBody, labels })
    });
    const issueData = await issueResp.json();

    if (issueResp.ok) {
      results.steps.push({
        step: 'create_issue',
        number: issueData.number,
        url: issueData.html_url,
        status: 'ok'
      });
    } else {
      results.errors.push({ step: 'create_issue', error: issueData.message });
    }
  }

  // ── STEP 4: Create PR (if full_deploy with prTitle) ──
  if (plan.mode === 'full_deploy' && plan.prTitle && targetBranch !== plan.branch && GH_TOKEN) {
    const prBody = `## ${plan.prTitle}\n\n` +
      `Artifact: \`${plan.ghPath}\`\n` +
      `Deployed via Claude.ai MCP artifact deployer.\n\n` +
      results.steps.map(s => `- ${s.step}: ${s.status}`).join('\n');

    const prResp = await fetch(`https://api.github.com/repos/${owner}/${repoName}/pulls`, {
      method: 'POST', headers: ghHeaders,
      body: JSON.stringify({
        title: plan.prTitle,
        body: prBody,
        head: targetBranch,
        base: plan.branch
      })
    });
    const prData = await prResp.json();

    if (prResp.ok) {
      results.steps.push({
        step: 'create_pr',
        number: prData.number,
        url: prData.html_url,
        status: 'ok'
      });
    } else {
      results.errors.push({ step: 'create_pr', error: prData.message });
    }
  }

} catch (e) {
  results.errors.push({ step: 'unexpected', error: e.message });
}

// ── SUMMARY ──
const allOk = results.errors.length === 0;
const summary = {
  status: allOk ? 'success' : 'partial',
  mode: plan.mode,
  artifact: plan.name,
  steps_completed: results.steps.length,
  steps: results.steps,
  errors: results.errors.length > 0 ? results.errors : undefined
};

// Friendly message
const msgs = results.steps.map(s => {
  switch(s.step) {
    case 'create_n8n_workflow': return `✅ n8n workflow: ${s.url}`;
    case 'activate_workflow': return `✅ Workflow activated`;
    case 'github_commit': return `✅ Committed to GitHub: ${s.url}`;
    case 'create_issue': return `✅ Issue #${s.number}: ${s.url}`;
    case 'create_pr': return `✅ PR #${s.number}: ${s.url}`;
    case 'create_branch': return `✅ Branch: ${s.branch}`;
    default: return `✅ ${s.step}`;
  }
});
summary.message = msgs.join('\n');

return [{ json: summary }];"

results.errors : undefined\n};\n\n// Friendly message\nconst msgs = results.steps.map(s => {\n switch(s.step) {\n case 'create_n8n_workflow': return `✅ n8n workflow: ${s.url}`;\n case 'activate_workflow': return `✅ Workflow activated`;\n case 'github_commit': return `✅ Committed to GitHub: ${s.url}`;\n case 'create_issue': return `✅ Issue #${s.number}: ${s.url}`;\n case 'create_pr': return `✅ PR #${s.number}: ${s.url}`;\n case 'create_branch': return `✅ Branch: ${s.branch}`;\n default: return `✅ ${s.step}`;\n }\n});\nsummary.message = msgs.join('\\n');\n\nreturn [{ json: summary }];"
      },
