        250,
        300
      ],
      "webhookId": "finance-handler"
    },
    {
      "parameters": {

"jsCode": "const event = $input.item.json;
const payload = event.payload || {};

let message = '';
let icon = '';

switch (event.event_type) {
  case 'finance_task.created':
    icon = '📋';
    message = `**${icon} Finance Task Created**\n\n**Task:** ${payload.task_name || 'Unknown'}\n**BIR Form:** ${payload.bir_form || 'N/A'}\n**Period:** ${payload.period_covered || 'N/A'}\n**Employee:** ${payload.employee_code || 'N/A'}\n**Prep Deadline:** ${payload.prep_deadline || 'N/A'}\n\n[View in Odoo](${$env.ODOO_BASE_URL}/web#id=${payload.task_id}&model=project.task)`;
    break;

  case 'finance_task.in_progress':
    icon = '🔄';
    message = `**${icon} Finance Task In Progress**\n\n**Task:** ${payload.task_name || 'Unknown'}\n**BIR Form:** ${payload.bir_form || 'N/A'}\n**Assigned to:** ${payload.assigned_to || 'Unknown'}\n\n[View in Odoo](${$env.ODOO_BASE_URL}/web#id=${payload.task_id}&model=project.task)`;
    break;

  case 'finance_task.submitted':
    icon = '✅';
    message = `**${icon} Finance Task Submitted**\n\n**Task:** ${payload.task_name || 'Unknown'}\n**BIR Form:** ${payload.bir_form || 'N/A'}\n**Status:** ${payload.status || 'Submitted'}\n\n[View in Odoo](${$env.ODOO_BASE_URL}/web#id=${payload.task_id}&model=project.task)`;
    break;

  case 'finance_task.approved':
    icon = '✅';
    message = `**${icon} Finance Task Approved**\n\n**Task:** ${payload.task_name || 'Unknown'}\n**BIR Form:** ${payload.bir_form || 'N/A'}\n**Status:** ${payload.status || 'Approved'}\n\n[View in Odoo](${$env.ODOO_BASE_URL}/web#id=${payload.task_id}&model=project.task)`;
    break;

