{
  "name": "Google Workspace Events Handler",
  "nodes": [
    {
      "parameters": {
        "httpMethod": "POST",
        "path": "workspace-webhook",
        "options": {
          "rawBody": true
        }
      },
      "id": "workspace-webhook",
      "name": "Workspace Webhook",
      "type": "n8n-nodes-base.webhook",
      "typeVersion": 1.1,
      "position": [240, 300],
      "webhookId": "workspace-events-webhook"
    },
    {
      "parameters": {
        "jsCode": "// Parse and categorize Workspace event
const payload = $input.first().json;
const headers = $input.first().headers;

// Determine event source and type
let eventSource = 'unknown';
let eventType = 'unknown';
let eventData = {};

// Google Drive changes
if (payload.kind === 'drive#change' || payload.kind === 'drive#changes') {
  eventSource = 'google_drive';
  eventType = payload.type || 'change';
  eventData = {
    fileId: payload.fileId,
    time: payload.time,
    removed: payload.removed || false,
    file: payload.file || null
  };
}
// Google Docs edits (via Apps Script webhook)
else if (payload.documentId || payload.source === 'google_docs') {
  eventSource = 'google_docs';
  eventType = payload.eventType || 'edit';
  eventData = {
    documentId: payload.documentId,
    documentTitle: payload.documentTitle,
    editedBy: payload.editedBy,
    changeType: payload.changeType
  };
}
// Gmail new email (via Gmail API push notification)
else if (payload.emailAddress || payload.historyId) {
  eventSource = 'gmail';
  eventType = 'new_message';
  eventData = {
    emailAddress: payload.emailAddress,
    historyId: payload.historyId
  };
}
// Google Sheets changes
else if (payload.spreadsheetId || payload.source === 'google_sheets') {
  eventSource = 'google_sheets';
  eventType = payload.eventType || 'edit';
  eventData = {
    spreadsheetId: payload.spreadsheetId,
    sheetName: payload.sheetName,
    range: payload.range,
    editedBy: payload.editedBy
  };
}

return {
  json: {
    eventSource,
    eventType,
