"jsCode": "// Extract closing tasks that require journal entries
// Month-End Close tasks map to specific account.move patterns:
//
// Phase I: Payroll JEs, Tax Provisions, Rent/Lease entries
// Phase II: Depreciation, Amortization, Corporate accruals
// Phase III: WIP reclassifications, Client billing accruals
// Phase IV: VAT entries, Expense reclassifications
// Phase V: Sign-off (no JE, just approval)

const tasksData = $node['Fetch Pending Approval Tasks'].json;

function parseTasks(data) {
  if (!data || !data.params) return [];
  const param = data.params.param;
  if (!param || !param.value || !param.value.array) return [];
  const items = param.value.array.data.value;
  if (!Array.isArray(items)) return items ? [items] : [];
  return items.map(item => {
    const members = item.struct.member;
    const task = {};
    members.forEach(m => {
      task[m.name] = m.value.string || m.value.int || '';
    });
    return task;
  });
}

const tasks = parseTasks(tasksData);

// Classify tasks by journal entry type
const JOURNAL_PATTERNS = {
  'Payroll & Personnel': {
    journal: 'HR',
    account_debit: '621xxx',
    account_credit: '214xxx',
    description: 'Payroll accrual / final pay / SL conversion'
  },
  'Tax & Provisions': {
    journal: 'MISC',
    account_debit: '637xxx',
    account_credit: '214xxx',
    description: 'Tax provision / PPB provision'
  },
  'Rent & Leases': {
    journal: 'MISC',
    account_debit: '635xxx',
    account_credit: '165xxx',
    description: 'Rental income/expense amortization'
  },
  'Accruals & Expenses': {
    journal: 'MISC',
    account_debit: '636xxx',
    account_credit: '214xxx',
    description: 'General expense accrual'
  },
  'Amortization & Corporate': {
    journal: 'MISC',
    account_debit: '681xxx',
    account_credit: '28xxxx',
    description: 'Depreciation / amortization'
  },
  'VAT & Taxes': {
    journal: 'TAX',
    account_debit: '445xxx',
    account_credit: '445xxx',
    description: 'Input/Output VAT compilation'
  },
  'WIP/OOP Management': {
    journal: 'SAL',
    account_debit: '370xxx',
    account_credit: '370xxx',
    description: 'WIP/OOP reclassification'
  },
  'Client Billings': {
    journal: 'SAL',
    account_debit: '411xxx',
    account_credit: '370xxx',
    description: 'Revenue accrual from client billing'
  }
};

const journalJobs = [];

for (const task of tasks) {
  const name = task.name || '';
  const desc = task.description || '';

  // Extract category from task name: [CODE] Category: Description
  const categoryMatch = name.match(/\]\s*([^:]+):/);
  const category = categoryMatch ? categoryMatch[1].trim() : null;

  // Skip Sign-off tasks (no JE needed)
  if (category === 'Sign-off') continue;

  const pattern = category ? JOURNAL_PATTERNS[category] : null;

  journalJobs.push({
    task_id: task.id,
    task_name: name,
    category: category,
    description: desc,
    deadline: task.date_deadline,
    journal_pattern: pattern,
    needs_ai_validation: true,
    project: task.project_id
  });
}

return [{
  json: {
    journal_jobs: journalJobs,
    job_count: journalJobs.length,
    categories: [...new Set(journalJobs.map(j => j.category).filter(Boolean))]
  }
}];"

