  };
}

const approved = (validationResult.validated_entries || []).filter(e => e.status === 'approved');
const needsReview = (validationResult.validated_entries || []).filter(e => e.status === 'needs_review');
const rejected = (validationResult.validated_entries || []).filter(e => e.status === 'rejected');

