"jsCode": "// BIR e-Filing Ecosystem Integration
// ====================================
// This workflow bridges Odoo 19 BIR form data with the BIR electronic
// filing systems. The Philippines BIR has 3 e-filing portals:
//
// 1. eFPS (Electronic Filing and Payment System)
//    - URL: https://efps.bir.gov.ph
//    - For: Large taxpayers, monthly/quarterly returns
//    - Forms: 1601-C, 0619-E, 2550M, 2550Q, 1601-EQ, 1702Q
//    - Method: Web submission with .dat file upload
//
// 2. eBIRForms (Electronic BIR Forms)
//    - URL: https://ebirforms.bir.gov.ph
//    - For: All taxpayers, offline preparation + online submission
//    - Forms: All BIR forms
//    - Method: JSON/XML data import into eBIRForms desktop app
//
// 3. eAFS (Electronic Audited Financial Statements)
//    - URL: https://eafs.bir.gov.ph
//    - For: Annual financial statements submission
//    - Forms: 1702-RT (with AFS attachments)
//    - Method: PDF upload
//
// This workflow:
//   Step 1: Validate - Check form data completeness and BIR computation rules
//   Step 2: Package  - Generate .dat files + eBIRForms JSON for upload
//   Step 3: Submit   - Prepare submission package with audit trail

const webhookData = $node['Webhook (e-File Request)']?.json || {};

// Default action is 'validate' (safest)
const action = webhookData.action || 'validate';
const formType = webhookData.form_type || null;
const period = webhookData.period || null;

// BIR e-Filing portal routing
const EFILING_ROUTES = {
  // Monthly returns → eFPS
  '1601-C':  { portal: 'eFPS', url: 'https://efps.bir.gov.ph', method: 'dat_upload' },
  '0619-E':  { portal: 'eFPS', url: 'https://efps.bir.gov.ph', method: 'dat_upload' },
  '2550M':   { portal: 'eFPS', url: 'https://efps.bir.gov.ph', method: 'dat_upload' },
  // Quarterly returns → eFPS
  '2550Q':   { portal: 'eFPS', url: 'https://efps.bir.gov.ph', method: 'dat_upload', attachments: ['SLSP'] },
  '1601-EQ': { portal: 'eFPS', url: 'https://efps.bir.gov.ph', method: 'dat_upload', attachments: ['QAP'] },
  '1702Q':   { portal: 'eFPS', url: 'https://efps.bir.gov.ph', method: 'form_submit' },
  // Annual returns → eFPS + eAFS
  '1702-RT': { portal: 'eFPS+eAFS', url: 'https://efps.bir.gov.ph', eafs_url: 'https://eafs.bir.gov.ph', method: 'form_submit', attachments: ['AFS'] },
  '1604-CF': { portal: 'eBIRForms', url: 'https://ebirforms.bir.gov.ph', method: 'dat_upload', attachments: ['Alphalist'] },
  '1604-E':  { portal: 'eBIRForms', url: 'https://ebirforms.bir.gov.ph', method: 'dat_upload', attachments: ['SAWT'] }
};

// Company TIN for filing
const companyTIN = $env.N8N_BIR_COMPANY_TIN || '000-000-000-000';
const companyRDO = $env.N8N_BIR_COMPANY_RDO || '000';

