      "name": "Plane Webhook",
      "type": "n8n-nodes-base.webhook",
      "typeVersion": 1,
      "position": [250, 300]
    },
    {
      "parameters": {
        "functionCode": "// Validate HMAC-SHA256 signature\nconst crypto = require('crypto');\nconst secret = $env.PLANE_WEBHOOK_SECRET;\nconst signature = $input.first().headers['x-plane-signature'];\nconst body = $input.first().body;\n\nconst expected = crypto.createHmac('sha256', secret)\n  .update(JSON.stringify(body))\n  .digest('hex');\n\nif (signature !== expected) {\n  throw new Error('HMAC signature validation failed');\n}\n\n// Extract commitment signal\nconst event = body;\nconst issue = event.data || {};\nconst state = issue.state_detail?.name || '';\nconst labels = (issue.labels || []).map(l => l.name || l);\n\n// Only process commitment signals\nconst isCommitment = state === 'In Progress' || labels.includes('commit');\n\nreturn [{\n  json: {\n    should_sync: isCommitment,\n    plane_project_id: issue.project || event.project,\n    plane_issue_id: issue.id,\n    title: issue.name,\n    description: issue.description_html || '',\n    priority: issue.priority || 'none',\n    state: state,\n    labels: labels,\n    idempotency_key: `plane:plane_to_odoo:${issue.id}:${event.created_at || new Date().toISOString()}`\n  }\n}];"
      },
