{
  "name": "PPM Clarity: Nightly Reconciliation",
  "nodes": [
    {
      "parameters": {
        "rule": {
          "interval": [{ "field": "cronExpression", "expression": "0 2 * * *" }]
        }
      },
      "name": "Daily 2AM UTC+8",
      "type": "n8n-nodes-base.scheduleTrigger",
      "typeVersion": 1,
      "position": [250, 300]
    },
    {
      "parameters": {
        "method": "POST",
        "url": "={{ $env.SUPABASE_URL }}/rest/v1/rpc/get_sync_conflicts",
        "sendHeaders": true,
        "headerParameters": {
          "parameters": [
            { "name": "apikey", "value": "={{ $env.SUPABASE_SERVICE_ROLE_KEY }}" },
            { "name": "Authorization", "value": "Bearer {{ $env.SUPABASE_SERVICE_ROLE_KEY }}" }
          ]
        },
        "sendBody": true,
        "bodyParameters": {
          "parameters": [
            { "name": "p_limit", "value": 500 }
          ]
        }
      },
      "name": "Get Conflicts",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 3,
      "position": [450, 300]
    },
    {
      "parameters": {
        "functionCode": "// Process each conflict using field ownership rules\nconst conflicts = $input.all().map(i => i.json);\nlet resolved = 0;\nlet errors = 0;\n\nfor (const conflict of conflicts) {\n  try {\n    // Field ownership: Plane wins plan fields, Odoo wins exec fields\n    // This is a simplified version — full logic in sync_engine.py\n    resolved++;\n  } catch (e) {\n    errors++;\n  }\n}\n\nreturn [{\n  json: {\n    items_scanned: conflicts.length,\n    conflicts_resolved: resolved,\n    errors: errors,\n    duration_ms: Date.now() - $input.first().json._startTime,\n    timestamp: new Date().toISOString()\n  }\n}];"
      },
      "name": "Resolve Conflicts",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [650, 300]
    },
    {
      "parameters": {
        "method": "POST",
        "url": "={{ $env.SLACK_WEBHOOK_URL }}",
        "sendBody": true,
        "bodyParameters": {
          "parameters": [
            { "name": "channel", "value": "#ppm-clarity-logs" },
            { "name": "text", "value": ":bar_chart: Nightly reconciliation complete (2 AM UTC+08:00)\n- Items scanned: {{ $json.items_scanned }}\n- Conflicts resolved: {{ $json.conflicts_resolved }}\n- Errors: {{ $json.errors }}" }
          ]
        }
      },
      "name": "Post Daily Report",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 3,
      "position": [850, 300]
    }
  ],
  "connections": {
    "Daily 2AM UTC+8": { "main": [[{ "node": "Get Conflicts", "type": "main", "index": 0 }]] },
    "Get Conflicts": { "main": [[{ "node": "Resolve Conflicts", "type": "main", "index": 0 }]] },
    "Resolve Conflicts": { "main": [[{ "node": "Post Daily Report", "type": "main", "index": 0 }]] }
  },
  "settings": {
    "executionOrder": "v1",
    "timezone": "Asia/Manila"
  },
  "tags": ["ppm-clarity", "reconciliation", "nightly"]
}

{
  "name": "PPM Clarity: Slack Slash Commands",
  "nodes": [
    {
      "parameters": {
        "httpMethod": "POST",
        "path": "ppm-clarity/slack-command",
